class Solution {
public:
    int racecar(int target) {
        int n = 1;
        while (n <= target) n <<= 1;
        vector<int> dp(n + 1, 1e9);
        queue<pair<int, int>> q;
        dp[0] = 0;
        q.push({0, 0});
        while (!q.empty()) {
            auto [pos, step] = q.front(); q.pop();
            if (pos == target) return step;
            int speed = (pos + step) / (step + 1);
            if (pos + speed <= target) {
                int next = pos + speed;
                if (dp[next] > dp[pos] + 1) {
                    dp[next] = dp[pos] + 1;
                    q.push({next, step + 1});
                }
            }
            if (speed > 0) {
                int next = pos + 1;
                if (dp[next] > dp[pos] + 1) {
                    dp[next] = dp[pos] + 1;
                    q.push({next, 1});
                }
            } else {
                int next = pos + 1;
                if (dp[next] > dp[pos] + 2) {
                    dp[next] = dp[pos] + 2;
                    q.push({next, -1});
                }
            }
        }
        return -1;
    }
};
```

